import { _decorator, Component, director, Node, Label, Button, ScrollView, Prefab, instantiate } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('ShopScene')
export class ShopScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Button)
    incenseTabBtn: Button = null;
    
    @property(Button)
    equipmentTabBtn: Button = null;
    
    @property(Button)
    giftTabBtn: Button = null;
    
    @property(ScrollView)
    shopListScrollView: ScrollView = null;
    
    @property(Node)
    shopItemPrefab: Node = null;
    
    @property(Label)
    yuanbaoLabel: Label = null;
    
    private currentTab: string = 'incense';
    
    private shopItems = {
        incense: [
            { id: 'incense_sticks', name: '线香', price: 10, currency: 'yuanbao', icon: '📿', desc: '供奉用的线香' },
            { id: 'candles', name: '蜡烛', price: 20, currency: 'yuanbao', icon: '🕯️', desc: '供奉用的蜡烛' },
            { id: 'gold_paper', name: '金纸', price: 30, currency: 'yuanbao', icon: '📜', desc: '供奉用的金纸' },
            { id: 'fruits', name: '供果', price: 50, currency: 'yuanbao', icon: '🍎', desc: '供奉用的水果' },
            { id: 'incense_sticks_pack', name: '线香礼包(10个)', price: 90, currency: 'yuanbao', icon: '📿', desc: '10支线香' },
            { id: 'candles_pack', name: '蜡烛礼包(10个)', price: 180, currency: 'yuanbao', icon: '🕯️', desc: '10支蜡烛' }
        ],
        equipment: [
            { id: 'wood_sword', name: '桃木剑', price: 100, currency: 'incense_money', icon: '⚔️', desc: '攻击+10' },
            { id: 'bronze_mirror', name: '青铜镜', price: 200, currency: 'incense_money', icon: '🪞', desc: '防御+5' },
            { id: 'duster_bronze', name: '青铜拂尘', price: 500, currency: 'yuanbao', icon: '🧹', desc: '攻击+25' }
        ],
        gift: [
            { id: 'first_charge', name: '首充礼包', price: 6, currency: 'CNY', icon: '🎁', desc: '首充6元，送888元宝' },
            { id: 'month_card', name: '月卡', price: 30, currency: 'CNY', icon: '📅', desc: '30天，每日领取100元宝' },
            { id: 'week_card', name: '周卡', price: 12, currency: 'CNY', icon: '📆', desc: '7天，每日领取50元宝' }
        ]
    };
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.incenseTabBtn.node.on(Button.EventType.CLICK, () => this.onTabClick('incense'), this);
        this.equipmentTabBtn.node.on(Button.EventType.CLICK, () => this.onTabClick('equipment'), this);
        this.giftTabBtn.node.on(Button.EventType.CLICK, () => this.onTabClick('gift'), this);
    }
    
    start() {
        this.updateCurrency();
        this.updateShopList();
    }
    
    updateCurrency() {
        const player = GameManager.getInstance().playerData;
        this.yuanbaoLabel.string = `元宝: ${player.getCurrency('yuanbao')}`;
    }
    
    onTabClick(tab: string) {
        this.currentTab = tab;
        this.updateShopList();
    }
    
    updateShopList() {
        const content = this.shopListScrollView.content;
        content.removeAllChildren();
        
        const items = this.shopItems[this.currentTab];
        
        for (const item of items) {
            const node = instantiate(this.shopItemPrefab);
            
            node.getChildByName('IconLabel').getComponent(Label).string = item.icon;
            node.getChildByName('NameLabel').getComponent(Label).string = item.name;
            node.getChildByName('DescLabel').getComponent(Label).string = item.desc;
            node.getChildByName('PriceLabel').getComponent(Label).string = 
                `${item.price} ${item.currency === 'CNY' ? '元' : item.currency === 'yuanbao' ? '元宝' : '香火钱'}`;
            
            const buyBtn = node.getChildByName('BuyBtn').getComponent(Button);
            buyBtn.node.on(Button.EventType.CLICK, () => this.onBuy(item), this);
            
            content.addChild(node);
        }
    }
    
    onBuy(item: any) {
        if (item.currency === 'CNY') {
            // 调用支付接口
            console.log(`支付${item.price}元购买${item.name}`);
            return;
        }
        
        const player = GameManager.getInstance().playerData;
        
        if (!player.costCurrency(item.currency, item.price)) {
            console.log(`${item.currency}不足`);
            return;
        }
        
        // 添加物品
        if (item.id.includes('pack')) {
            // 礼包
            const count = parseInt(item.desc.match(/\d+/)[0]);
            const itemType = item.id.replace('_pack', '');
            player.addCurrency(itemType, count);
        } else {
            player.addCurrency(item.id, 1);
        }
        
        this.updateCurrency();
        console.log(`购买成功: ${item.name}`);
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
}
